SELECT ta.application_id AS applicationId, ta.team_id AS teamId, it.team_name AS teamName, ta.student_id AS studentId, s.name AS studentName, s.student_number AS studentNumber, ta.application_letter AS applicationLetter, ta.status, ta.apply_time AS applyTime, ta.review_time AS reviewTime FROM team_applications ta JOIN innovation_teams it ON ta.team_id = it.team_id JOIN students s ON ta.student_id = s.user_id WHERE 1=1
AND ta.team_id = #{teamId}
AND ta.student_id = #{studentId}
AND ta.status = #{status}
ORDER BY ta.apply_time DESC LIMIT #{limit} OFFSET #{offset}

